def flatten(nested_list):
    flat = []
    for item in nested_list:
        if type(item) == list:
            flat.extend(flatten(item))
        else:
            flat.append(item)
    return flat

def count_words(text):
    words = text.split(' ')
    counts = {}
    for word in words:
        word = word.lower().strip('.,!?')
        if word in counts:
            counts[word] = counts[word] + 1
        else:
            counts[word] = 0
    return counts
